//! Auto-generated Unicode lookup tables.
//!
//! Tables are generated by `aterm build rust` from Unicode 16.0
//! Character Database files. Do not edit the generated files directly.
//!
//! Modules:
//! - [`width`] — East Asian Width / zero-width classification (UAX #11).
//! - [`gcb`] — Grapheme_Cluster_Break property + UAX #29 break matrix.
//!
//! Only `width`'s API is exported from the crate; `gcb` is `pub(crate)` because
//! the segmentation state machine lives in [`crate::grapheme_iter`] and
//! consumes the GCB tables directly.

pub(crate) mod gcb;
pub(crate) mod width;

// Re-export commonly used functions
pub use width::{char_width, char_width_cjk, is_ambiguous_width, str_width, str_width_cjk};
